BEGIN;
-- Chunk E: comparison tables + glossary + checklists (part 1/4)
INSERT INTO comparison_tables (table_number, title, description, columns_json, rows_json, footnote, guidance_json, display_order) VALUES
  (1, 'Residential Steep-Slope Systems Comparison', 'Comparison of residential pitched-roof systems USA Flat Roof works on or encounters in inspections.', '[{"key":"system","label":"System"},{"key":"usa_flat_roof_position","label":"USA Flat Roof Position"},{"key":"norcal_lifespan","label":"NorCal Field Lifespan"},{"key":"cost_tier","label":"Cost Tier"},{"key":"customer_type","label":"Customer Type"},{"key":"key_strength","label":"Key Strength"},{"key":"key_limitation","label":"Key Limitation"}]'::jsonb, '[{"system":"Composition Shingle (3-tab)","usa_flat_roof_position":"Installs / repairs / replaces","norcal_lifespan":"15–20 years","cost_tier":"Lowest","customer_type":"Budget-conscious; older homes","key_strength":"Affordable; familiar to crews","key_limitation":"Shorter lifespan; less wind resistance"},{"system":"Composition Shingle (Architectural)","usa_flat_roof_position":"Installs / repairs / replaces","norcal_lifespan":"18–25 years","cost_tier":"Low–mid","customer_type":"Standard residential; current industry default","key_strength":"Cost-effective; broad product selection","key_limitation":"Vulnerable to ventilation-driven aging"},{"system":"Composition Shingle (Designer)","usa_flat_roof_position":"Installs / repairs / replaces","norcal_lifespan":"25–40 years","cost_tier":"Mid–high","customer_type":"Premium homes; slate / shake aesthetic preference","key_strength":"Mimics premium materials at lower cost","key_limitation":"Higher cost than architectural"},{"system":"Concrete Tile","usa_flat_roof_position":"Repair and maintenance only","norcal_lifespan":"Tiles: 50+ years; Underlayment: 20–30 years","cost_tier":"Mid–high (original install)","customer_type":"NorCal tract homes 1980s–2010s; Mediterranean style","key_strength":"Long tile life; fire-resistant","key_limitation":"Underlayment ages on different timeline; full re-felt referred out"},{"system":"Clay Tile","usa_flat_roof_position":"Recognize; refer out","norcal_lifespan":"Tiles: 50+ years; Underlayment: 20–30 years","cost_tier":"High","customer_type":"Older / higher-end homes; Mediterranean style","key_strength":"Distinctive aesthetic; very long tile life","key_limitation":"Specialty trade; outside USA Flat Roof scope"},{"system":"Real Wood Shake","usa_flat_roof_position":"Recognize; refer out","norcal_lifespan":"20–35 years (varies widely)","cost_tier":"High","customer_type":"Rural / older homes; permitted areas only","key_strength":"Natural appearance","key_limitation":"Fire code restrictions in many CA jurisdictions; outside USA Flat Roof scope"},{"system":"Synthetic / Composite Tile or Slate","usa_flat_roof_position":"Limited; escalate","norcal_lifespan":"30–50 years","cost_tier":"High","customer_type":"Recent custom homes","key_strength":"Lighter than real tile / slate; long-life","key_limitation":"Specialty product; limited USA Flat Roof scope"},{"system":"Stone-Coated Metal","usa_flat_roof_position":"Limited; escalate","norcal_lifespan":"30–50 years","cost_tier":"Mid–high","customer_type":"Niche; fire-prone areas","key_strength":"Lightweight; long-life; fire-resistant","key_limitation":"Specialty trade; limited USA Flat Roof scope"},{"system":"Standing-Seam Metal","usa_flat_roof_position":"Recognize; refer out","norcal_lifespan":"30–50+ years","cost_tier":"High","customer_type":"Modern / rural / agricultural","key_strength":"Long-life; minimal maintenance","key_limitation":"Specialty trade; outside USA Flat Roof scope"},{"system":"Real Slate","usa_flat_roof_position":"Recognize; refer out","norcal_lifespan":"75–100+ years","cost_tier":"Highest","customer_type":"Historic / high-end homes","key_strength":"Longest service life; distinctive","key_limitation":"Heaviest material; specialty trade; rare in NorCal"}]'::jsonb, '[VERIFY LOCALLY] Lifespan ranges reflect NorCal conditions and reasonable maintenance. Confirm with USA Flat Roof field experience.', NULL, 1),
  (2, 'Commercial Flat-Roof Systems Comparison', 'Comparison of commercial flat-roof systems USA Flat Roof works on or encounters in inspections.', '[{"key":"system","label":"System"},{"key":"usa_flat_roof_position","label":"USA Flat Roof Position"},{"key":"norcal_lifespan","label":"NorCal Field Lifespan"},{"key":"cost_tier","label":"Cost Tier"},{"key":"best_application","label":"Best Application"},{"key":"key_strength","label":"Key Strength"},{"key":"key_limitation","label":"Key Limitation"}]'::jsonb, '[{"system":"TPO (60-mil mech-attached)","usa_flat_roof_position":"Installs (flagship)","norcal_lifespan":"18–25 years","cost_tier":"Mid","best_application":"Standard commercial; new construction","key_strength":"Cost-competitive; reflective; strong field track record","key_limitation":"Seam-dependent; vulnerable to mechanical damage from trades"},{"system":"PVC","usa_flat_roof_position":"Installs (premium)","norcal_lifespan":"20–30 years","cost_tier":"Mid–high","best_application":"Restaurants; kitchens; chemical / grease exposure","key_strength":"Longest single-ply track record; chemical resistance","key_limitation":"Higher cost; plasticizer migration on aged systems"},{"system":"EPDM","usa_flat_roof_position":"Limited scope; escalate","norcal_lifespan":"20–30 years","cost_tier":"Mid","best_application":"Older commercial; some new niche","key_strength":"Long track record; flexible","key_limitation":"Limited USA Flat Roof scope; mostly black (Title 24 implications)"},{"system":"Modified Bitumen (Self-Adhered)","usa_flat_roof_position":"Installs (only self-adhered)","norcal_lifespan":"15–25 years","cost_tier":"Mid","best_application":"Multifamily; occupied buildings; fire-restricted environments","key_strength":"Multi-ply redundancy; no open flame at install","key_limitation":"Heavier than single-ply; substrate-sensitive at install"},{"system":"BUR (Built-Up Roofing)","usa_flat_roof_position":"Restores / recovers / replaces (no new install)","norcal_lifespan":"20–40+ years (legacy installs often exceed)","cost_tier":"Legacy","best_application":"Older commercial; encountered on inspection","key_strength":"Longest field track record of any flat-roof system","key_limitation":"No new BUR installs; layer count drives recommendation"},{"system":"SPF","usa_flat_roof_position":"Installs (3 use cases)","norcal_lifespan":"Foam: 25+ years; Topcoat: 10–15 years","cost_tier":"Mid–high","best_application":"Ponding correction; BUR recover; insulation upgrade","key_strength":"Tapers slope during application; provides insulation","key_limitation":"Topcoat recoat required; site-condition sensitive"},{"system":"Silicone Coating","usa_flat_roof_position":"Installs (restoration)","norcal_lifespan":"10–15 years","cost_tier":"Low–mid","best_application":"Aged TPO / mod-bit / BUR with sound substrate","key_strength":"Extends life cost-effectively; UV-resistant","key_limitation":"Substrate-dependent; doesn''t fix ponding"},{"system":"Acrylic Coating","usa_flat_roof_position":"Reference; not typically proposed","norcal_lifespan":"5–10 years","cost_tier":"Low","best_application":"Specific applications where silicone isn''t ideal","key_strength":"Lower cost; recoat-friendly","key_limitation":"Less ponding tolerance than silicone; limited USA Flat Roof scope"}]'::jsonb, NULL, NULL, 2),
  (3, 'Lifespan Comparison', 'All ranges are NorCal field experience under reasonable maintenance. Specific roofs vary based on installation quality, ventilation, exposure, drainage, and maintenance.', '[{"key":"system","label":"System"},{"key":"typical_lifespan","label":"Typical Field Lifespan"}]'::jsonb, '[{"system":"Composition Shingle (3-tab)","typical_lifespan":"15–20 years"},{"system":"Composition Shingle (Architectural)","typical_lifespan":"18–25 years"},{"system":"Composition Shingle (Designer)","typical_lifespan":"25–40 years"},{"system":"Concrete Tile (tiles)","typical_lifespan":"50+ years"},{"system":"Concrete Tile (underlayment)","typical_lifespan":"20–30 years"},{"system":"Clay Tile (tiles)","typical_lifespan":"50–100+ years"},{"system":"Clay Tile (underlayment)","typical_lifespan":"20–30 years"},{"system":"TPO (60-mil mech-attached)","typical_lifespan":"18–25 years"},{"system":"PVC","typical_lifespan":"20–30 years"},{"system":"EPDM","typical_lifespan":"20–30 years"},{"system":"Modified Bitumen (self-adhered, 2-ply)","typical_lifespan":"15–25 years"},{"system":"BUR","typical_lifespan":"20–40+ years (legacy installs often exceed)"},{"system":"SPF (foam)","typical_lifespan":"25+ years with topcoat maintenance"},{"system":"SPF (topcoat between recoats)","typical_lifespan":"10–15 years"},{"system":"Silicone Coating","typical_lifespan":"10–15 years (extends substrate life)"},{"system":"Acrylic Coating","typical_lifespan":"5–10 years"},{"system":"Roof Rejuvenation","typical_lifespan":"Manufacturer-published extension range"},{"system":"Real Slate","typical_lifespan":"75–100+ years"}]'::jsonb, NULL, '{"guidance":{"what_reps_must_not_do":["Quote specific lifespan numbers (e.g., ''your roof has 7 years left'')","Equate manufacturer warranty length with these ranges","Treat the ranges as guarantees","Use the ranges to argue for or against replacement without inspection-supported reasoning"],"what_the_table_is_good_for":["Customer education on field expectations","Anchoring the ''age + condition'' conversation honestly","Comparing systems for new project conversations","Setting expectations on restoration vs replacement timing"]}}'::jsonb, 3),
  (4, 'Maintenance Needs Comparison', 'Maintenance commitment varies meaningfully across systems. Customers who want minimal maintenance should know which systems require active attention.', '[{"key":"system","label":"System"},{"key":"maintenance_intensity","label":"Maintenance Intensity"},{"key":"typical_recurring_items","label":"Typical Recurring Items"}]'::jsonb, '[{"system":"Composition Shingle","maintenance_intensity":"Low–moderate","typical_recurring_items":"Annual inspection; gutter cleaning; debris removal; minor sealant; ventilation check"},{"system":"Concrete Tile","maintenance_intensity":"Moderate","typical_recurring_items":"Annual inspection; debris from valleys; biological growth treatment; broken tile replacement; mortar at ridge"},{"system":"TPO","maintenance_intensity":"Moderate","typical_recurring_items":"Annual inspection; drain clearing; seam check; walk-pad maintenance; sealant refresh at details"},{"system":"PVC","maintenance_intensity":"Moderate","typical_recurring_items":"Same as TPO; chemical/grease cleanup at exhaust vents on restaurants"},{"system":"Modified Bitumen","maintenance_intensity":"Moderate","typical_recurring_items":"Annual inspection; drain clearing; seam check; sealant refresh; granule monitoring"},{"system":"BUR","maintenance_intensity":"Moderate–high","typical_recurring_items":"Annual inspection; gravel redistribution; drain clearing; seam check; coating refresh on coated BUR"},{"system":"SPF","maintenance_intensity":"High","typical_recurring_items":"Annual inspection; topcoat recoat every 10–15 years (mandatory for warranty); damage repair to maintain UV protection"},{"system":"Silicone Coating","maintenance_intensity":"Low–moderate","typical_recurring_items":"Annual inspection; cleaning; eventual recoat in 10–15 years"},{"system":"Real Slate","maintenance_intensity":"Low","typical_recurring_items":"Periodic inspection; replacement of damaged slates only"}]'::jsonb, NULL, '{"patterns_worth_noting":["SPF is the highest-maintenance system on this list. The topcoat recoat schedule is not optional. Customers who don''t want a maintenance commitment should know this before choosing SPF.","Tile and BUR require regular attention to drainage and surface conditions. Both systems perform well under maintenance and degrade quickly without it.","Composition shingle is comparatively forgiving — but the trade-off is shorter lifespan and ventilation sensitivity.","Single-ply systems (TPO, PVC, EPDM) depend on detail maintenance more than field maintenance. The seams and details age faster than the membrane."]}'::jsonb, 4),
  (5, 'Repair Difficulty Comparison', 'Repair difficulty affects pricing, scheduling, and material sourcing. This table reflects the practical reality of repair work, not theoretical possibility.', '[{"key":"system","label":"System"},{"key":"repair_difficulty","label":"Repair Difficulty"},{"key":"common_challenges","label":"Common Challenges"}]'::jsonb, '[{"system":"Composition Shingle","repair_difficulty":"Easy–moderate","common_challenges":"Color matching on aged roofs; profile matching (3-tab vs architectural); discontinued products"},{"system":"Concrete Tile","repair_difficulty":"Moderate","common_challenges":"Tile profile and color matching; discontinued profiles; safe access (walk-on technique); underlayment rarely repaired (re-felt is full scope)"},{"system":"Clay Tile","repair_difficulty":"Difficult","common_challenges":"Specialty trade; tile sourcing harder than concrete; delicate handling"},{"system":"TPO","repair_difficulty":"Easy–moderate","common_challenges":"Welded patches require equipment; matching age-related color is challenging; substrate access for fasteners"},{"system":"PVC","repair_difficulty":"Easy–moderate","common_challenges":"Same as TPO; aged PVC may not weld as cleanly due to plasticizer migration"},{"system":"Modified Bitumen","repair_difficulty":"Moderate","common_challenges":"Self-adhered patches with primer; ensuring adhesion on aged surface; matching surface finish"},{"system":"BUR","repair_difficulty":"Moderate–difficult","common_challenges":"Asphalt-cement patches; gravel handling; pitch pan replacement; asbestos potential on older systems"},{"system":"SPF","repair_difficulty":"Moderate","common_challenges":"Foam repair requires equipment and trained applicator; topcoat patch requires color match; bird/rodent damage repair"},{"system":"Silicone Coating","repair_difficulty":"Easy","common_challenges":"Spot recoat with same chemistry; fabric reinforcement at high-stress areas"},{"system":"Real Slate","repair_difficulty":"Difficult","common_challenges":"Specialty trade; slate sourcing; fragile material"}]'::jsonb, NULL, NULL, 5),
  (6, 'Restoration Potential Comparison', 'Restoration is the option most often misrecommended. This table summarizes which systems qualify for restoration, under what conditions, and what disqualifies them.', '[{"key":"system","label":"System"},{"key":"restoration_option","label":"Restoration Option"},{"key":"qualifying_conditions","label":"Qualifying Conditions"},{"key":"disqualifying_conditions","label":"Disqualifying Conditions"}]'::jsonb, '[{"system":"Composition Shingle","restoration_option":"Fresh Roof rejuvenation","qualifying_conditions":"Roof in mid-life qualifying window; sound substrate; intact granule coverage; no active leaks; addressable detail repairs","disqualifying_conditions":"Roof outside qualifying age window; widespread granule loss; multiple damaged shingles; soft deck; active leaks"},{"system":"Concrete Tile","restoration_option":"Not applicable (no restoration; underlayment replacement is the alternative)","qualifying_conditions":"—","disqualifying_conditions":"Restoration coatings not appropriate for tile systems"},{"system":"TPO","restoration_option":"Silicone coating","qualifying_conditions":"Sound seams; no chronic ponding; addressable details; no wet insulation","disqualifying_conditions":"Wet insulation; chronic ponding; widespread seam failure; substrate degradation"},{"system":"PVC","restoration_option":"Silicone coating (with compatibility verification)","qualifying_conditions":"Sound substrate; no chronic ponding; addressable details; coating compatibility confirmed","disqualifying_conditions":"Plasticizer-driven cracking on aged PVC; ponding; wet insulation; coating compatibility issues"},{"system":"Modified Bitumen","restoration_option":"Silicone coating","qualifying_conditions":"Sound substrate; intact seams; no chronic ponding; addressable details","disqualifying_conditions":"Wet insulation; widespread alligatoring; failed seams; chronic ponding"},{"system":"BUR","restoration_option":"Silicone coating; SPF; TPO overlay","qualifying_conditions":"Single layer; sound substrate; no chronic ponding; no asbestos issues","disqualifying_conditions":"Multi-layer; wet insulation; severe ponding; asbestos requiring abatement"},{"system":"SPF","restoration_option":"Topcoat recoat","qualifying_conditions":"Foam in serviceable condition; topcoat at recoat window; no widespread foam exposure","disqualifying_conditions":"Widespread foam degradation; substrate failure; foam delamination"}]'::jsonb, NULL, '{"disqualifying_conditions_pattern":"Across systems, the same disqualifying conditions recur: wet insulation, chronic ponding, widespread substrate failure, roof outside qualifying age window, and asbestos requiring abatement. A rep who can name these conditions confidently knows when restoration is and isn''t appropriate without having to look it up."}'::jsonb, 6),
  (7, 'Common Failure Points Comparison', 'Roofs fail at predictable locations across systems. Knowing where to look accelerates inspection and helps reps explain to customers why ''leaks live at details, not the field.''', '[{"key":"system","label":"System"},{"key":"most_common_failure_locations","label":"Most Common Failure Locations"},{"key":"most_common_failure_modes","label":"Most Common Failure Modes"}]'::jsonb, '[{"system":"Composition Shingle","most_common_failure_locations":"Pipe boots; chimney flashing; sidewall step flashing; missing kick-out flashing; valleys","most_common_failure_modes":"Cracked pipe boots; failed sealant at chimney; missing kick-out causing fascia rot; valley wear"},{"system":"Concrete Tile","most_common_failure_locations":"Underlayment (the actual waterproofing); pipe boots; valley flashings; ridge mortar","most_common_failure_modes":"Underlayment age; tile-related leaks rare; broken tiles localized; ridge mortar deterioration"},{"system":"TPO","most_common_failure_locations":"Seams; pipe boots; HVAC curbs; drains","most_common_failure_modes":"Seam separation; pipe boot UV degradation; mechanical damage from trades; drain ring failure"},{"system":"PVC","most_common_failure_locations":"Seams (less common than TPO); pipe boots; details","most_common_failure_modes":"Plasticizer migration; weld inconsistencies on aged systems; detail aging"},{"system":"Modified Bitumen","most_common_failure_locations":"Seams; pipe boots; flashings; blistering","most_common_failure_modes":"Seam separation; blistering (moisture entrapment); flashing failure; granule loss exposing asphalt"},{"system":"BUR","most_common_failure_locations":"Pitch pans; flashings; drain rings; gravel-bare areas","most_common_failure_modes":"Sealant failure in pitch pans; alligatoring; ply separation; ponding-driven wear"},{"system":"SPF","most_common_failure_locations":"Topcoat (when worn); penetrations; bird/rodent damage areas","most_common_failure_modes":"Topcoat thinning exposing foam; foam UV degradation; impact damage at HVAC areas"},{"system":"Silicone Coating","most_common_failure_locations":"Ponded areas; high-stress detail areas; substrate underneath","most_common_failure_modes":"Coating wear in ponded areas; fabric exposure at seams; substrate failure under intact coating"},{"system":"Real Slate","most_common_failure_locations":"Slate fasteners; flashings","most_common_failure_modes":"Fastener failure (slate slips); flashing at chimneys and valleys"}]'::jsonb, NULL, '{"universal_pattern":"Across every roof system, leaks happen overwhelmingly at: penetrations (pipe boots, vents, skylights, drains), transitions (sidewalls, headwalls, parapets, dormers), edges (drip edge, parapet, scupper), valleys, and drains/scuppers. The middle of the field is the easiest part of any roof to waterproof. The details are the hardest."}'::jsonb, 7),
  (8, 'Sales Opportunity Comparison', 'Systems present different revenue opportunities across the customer relationship lifecycle. This table summarizes the typical pipeline.', '[{"key":"system","label":"System"},{"key":"new_install","label":"New Install"},{"key":"maintenance","label":"Maintenance"},{"key":"repair","label":"Repair"},{"key":"restoration","label":"Restoration"},{"key":"replacement","label":"Replacement"},{"key":"long_term_pipeline_value","label":"Long-Term Pipeline Value"}]'::jsonb, '[{"system":"Composition Shingle","new_install":"Yes","maintenance":"Yes (programs)","repair":"Frequent (high volume)","restoration":"Fresh Roof rejuvenation in qualifying window","replacement":"Yes (15–25 year cycle)","long_term_pipeline_value":"High — full cycle within USA Flat Roof scope"},{"system":"Concrete Tile","new_install":"No","maintenance":"Yes (programs)","repair":"Frequent (broken tiles, mortar, flashings)","restoration":"No coatings; underlayment is the long-term answer","replacement":"Refer out (specialty trade)","long_term_pipeline_value":"Moderate — repair and maintenance scope; replacement referred"},{"system":"TPO","new_install":"Yes (flagship)","maintenance":"Yes (programs)","repair":"Yes (seam, pipe boot, drain repairs)","restoration":"Silicone coating at appropriate stage","replacement":"Yes (18–25 year cycle)","long_term_pipeline_value":"High — full cycle within USA Flat Roof scope"},{"system":"PVC","new_install":"Yes (premium)","maintenance":"Yes (programs)","repair":"Yes","restoration":"Silicone coating with compatibility verification","replacement":"Yes (20–30 year cycle)","long_term_pipeline_value":"High — premium customer profile, full cycle"},{"system":"Modified Bitumen","new_install":"Yes (self-adhered)","maintenance":"Yes (programs)","repair":"Yes","restoration":"Silicone coating","replacement":"Yes (15–25 year cycle)","long_term_pipeline_value":"High — full cycle within USA Flat Roof scope"},{"system":"BUR","new_install":"No","maintenance":"Yes","repair":"Yes","restoration":"Silicone coating; TPO overlay; SPF","replacement":"Yes (replacement scope, no new BUR)","long_term_pipeline_value":"High — recover and replacement scope on legacy systems"},{"system":"SPF","new_install":"Yes (3 use cases)","maintenance":"Yes (high — recoat critical)","repair":"Yes","restoration":"Topcoat recoat (recurring)","replacement":"Long-term replacement","long_term_pipeline_value":"High — recurring topcoat revenue"},{"system":"Silicone Coating","new_install":"Yes (restoration product)","maintenance":"Yes","repair":"Yes","restoration":"Maintenance recoat","replacement":"Replacement when substrate fails","long_term_pipeline_value":"Moderate — bridge product; eventual replacement"},{"system":"Acrylic Coating","new_install":"No (typically)","maintenance":"Recognize on existing","repair":"Recognize","restoration":"Limited; usually refer to silicone","replacement":"Replacement as needed","long_term_pipeline_value":"Low — limited USA Flat Roof scope"},{"system":"EPDM","new_install":"No (typically)","maintenance":"Recognize","repair":"Limited","restoration":"Limited","replacement":"Refer or replacement scope","long_term_pipeline_value":"Low — limited USA Flat Roof scope"}]'::jsonb, NULL, '{"pipeline_math":["Initial inspection — establishes the relationship; honest recommendation drives trust","Maintenance enrollment — converts customers into ongoing relationships; predictable recurring revenue","Repair work — addressed as conditions develop; documented as part of ongoing maintenance","Restoration in qualifying window — Fresh Roof on shingle; silicone on commercial flat","Replacement at end of life — full-cycle relationship; documented history makes proposal and decision easier"]}'::jsonb, 8)
ON CONFLICT (table_number) DO UPDATE SET
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  columns_json = EXCLUDED.columns_json,
  rows_json = EXCLUDED.rows_json,
  footnote = EXCLUDED.footnote,
  guidance_json = EXCLUDED.guidance_json,
  display_order = EXCLUDED.display_order;
COMMIT;
